"use client";

import { useEffect, useId, useRef } from "react";
import { AnimatePresence, motion } from "framer-motion";
import { X } from "lucide-react";
import { ApplicationForm, type LeadSource } from "@/components/ui/application-form";

type ApplicationModalProps = {
  isOpen: boolean;
  leadSource: LeadSource;
  onClose: () => void;
  resetSignal?: number;
};

export function ApplicationModal({
  isOpen,
  leadSource,
  onClose,
  resetSignal = 0,
}: ApplicationModalProps) {
  const titleId = useId();
  const panelRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (!isOpen) {
      return;
    }

    const originalOverflow = document.body.style.overflow;
    document.body.style.overflow = "hidden";

    const handleKeyDown = (event: KeyboardEvent) => {
      if (event.key === "Escape") {
        onClose();
      }
    };

    document.addEventListener("keydown", handleKeyDown);
    return () => {
      document.body.style.overflow = originalOverflow;
      document.removeEventListener("keydown", handleKeyDown);
    };
  }, [isOpen, onClose]);

  return (
    <AnimatePresence>
      {isOpen && (
        <motion.div
          className="fixed inset-0 z-[80] flex items-center justify-center bg-[rgba(7,17,31,0.46)] px-4 py-6 backdrop-blur-xl"
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          exit={{ opacity: 0 }}
          onClick={onClose}
        >
          <motion.div
            ref={panelRef}
            role="dialog"
            aria-modal="true"
            aria-labelledby={titleId}
            initial={{ opacity: 0, scale: 0.96, y: 24 }}
            animate={{ opacity: 1, scale: 1, y: 0 }}
            exit={{ opacity: 0, scale: 0.96, y: 20 }}
            transition={{ type: "spring", stiffness: 160, damping: 18 }}
            className="surface-card-strong relative w-full max-w-3xl overflow-hidden p-5 sm:p-6 lg:p-7"
            onClick={(event) => event.stopPropagation()}
          >
            <div
              aria-hidden="true"
              className="pointer-events-none absolute left-[-6rem] top-[-5rem] h-40 w-40 rounded-full bg-[radial-gradient(circle,rgba(22,93,245,0.2),transparent_64%)] blur-2xl"
            />
            <div
              aria-hidden="true"
              className="pointer-events-none absolute bottom-[-6rem] right-[-5rem] h-48 w-48 rounded-full bg-[radial-gradient(circle,rgba(31,199,182,0.18),transparent_66%)] blur-3xl"
            />

            <div className="relative flex items-start justify-between gap-4">
              <div className="space-y-3">
                <div className="eyebrow">
                  <span className="h-2 w-2 rounded-full bg-emerald-400" />
                  <span>{leadSource}</span>
                </div>
                <div>
                  <h2
                    id={titleId}
                    className="text-2xl font-semibold tracking-tight text-[var(--foreground)] sm:text-3xl"
                  >
                    One application. Multiple industry-ready programs.
                  </h2>
                  <p className="mt-2 max-w-2xl text-sm leading-7 text-[var(--muted)] sm:text-base">
                    Tell us a bit about yourself and the kind of program you are
                    looking for. EduBh advisors will match you with the right options
                    at Manipal, Jain, and Sharda University Online.
                  </p>
                </div>
              </div>
              <button
                type="button"
                onClick={onClose}
                aria-label="Close application form"
                className="inline-flex h-10 w-10 shrink-0 items-center justify-center rounded-full border border-[rgba(109,132,170,0.16)] bg-white/82 text-[var(--muted)] shadow-[0_12px_26px_rgba(16,32,58,0.08)] transition hover:text-[var(--foreground)]"
              >
                <X className="h-4 w-4" />
              </button>
            </div>

            <div className="relative mt-6">
              <ApplicationForm
                leadSource={leadSource}
                resetSignal={resetSignal}
                className="rounded-[1.65rem] border border-white/65 bg-white/82 p-1 shadow-[0_16px_32px_rgba(16,32,58,0.06)] sm:p-2"
              />
            </div>
          </motion.div>
        </motion.div>
      )}
    </AnimatePresence>
  );
}
